    temp_dir = os.path.join(os.path.dirname(__file__), 'temp')
    if not os.path.exists(temp_dir):
        os.makedirs(temp_dir)

    temp_input_file = os.path.join(temp_dir, f"{os.path.basename(input_file)}.tmp")
    temp_output_file = os.path.join(temp_dir, f"{os.path.basename(output_file)}.out")

    with open(temp_input_file, "wb") as f:
        with open(input_file, "rb") as input_file_obj:
            f.write(input_file_obj.read())

